INSERT
  INTO
  		BOARD	
  		(
  		MEMBER_NO 
	 ,	BOARD_TITLE
	 ,	BOARD_CONTENT
	 ,	CATEGORY_NO
	  	)
VALUES
		(
		#{memberNo}
	 ,  #{boardTitle}
	 ,	#{boardContent}
	 ,	#{categoryNo}
		)

mapper.update:
UPDATE
		BOARD
   SET
		CATEGORY_NO = #{categoryNo}
	 ,	BOARD_TITLE = #{boardTitle}
	 ,	BOARD_CONTENT = #{boardContent}
 WHERE
		BOARD_NO = #{boardNo}
   AND
		MEMBER_NO = #{memberNo}

